import { LedgerRecord } from '../base/ledger-record';
import { LedgerHandle } from '../common/ledger-handle';
import { LedgerMeta } from '../common/ledger-meta';
import { BridgeCommand } from './bridge-entry';
import { LedgerEvent } from './ledger-event';
/**
 * Payload shape stored on `meta.output` of an event delivery record.
 *
 * - Effect deliveries (webhook or bridge) carry a signed
 *   `LedgerRecord<LedgerEvent>` — the exact envelope the receiver sees.
 * - DTC intent messages (prepare/commit/abort/status) carry a signed
 *   `LedgerRecord<BridgeCommand>` — no LedgerEvent exists for these.
 */
export type EventDeliveryOutput = LedgerRecord<LedgerEvent> | LedgerRecord<BridgeCommand>;
/**
 * Status of an event delivery — mirrors `event_delivery.status` on the
 * row. `running` is a transient state written while the handler's HTTP
 * call is in flight; the row flips to `delivered`/`failed`/`cancelled`
 * as soon as the call settles.
 */
export type EventDeliveryStatus = 'pending' | 'running' | 'failed' | 'delivered' | 'cancelled';
/**
 * Data shape of an event delivery record returned in API list responses.
 *
 * An event corresponds to one scheduler job thread (all retries of the same
 * delivery share a thread). The `handle` equals the thread UUID and is stable
 * across all reschedulings.
 *
 * `status` is NOT part of this data shape — it is carried in `meta.status`
 * of the wrapping `LedgerRecord`, following the standard ledger record envelope.
 *
 * Distinct from `LedgerEvent` which represents domain-level signals
 * (e.g. BridgeCreated, IntentUpdated). `LedgerEventDelivery` is an operational
 * record about the HTTP delivery attempt status.
 */
export type LedgerEventDelivery = {
    /**
     * Unique handle of the event — equals the scheduler job thread UUID.
     */
    handle: string;
    /**
     * Bridge handle if this is a bridge delivery event.
     */
    bridge?: LedgerHandle;
    /**
     * Effect handle if this is a webhook effect delivery event.
     */
    effect?: LedgerHandle;
    /**
     * Most representative AccessRecord type for this delivery.
     * For DTC bridge deliveries: 'intent'. For effect deliveries: derived from the signal.
     */
    record?: string;
    /**
     * Handle of the most representative record for this delivery.
     * For DTC bridge deliveries: the intent handle.
     * For effect deliveries: the handle of the record that triggered the signal.
     */
    linked?: string;
};
export type EventDeliveryMeta = Omit<LedgerMeta, 'owners' | 'domain' | 'labels' | 'secret'> & {
    /**
     * Number of delivery attempts made (0 = first attempt).
     */
    replay?: number;
    /**
     * Current status of the delivery.
     */
    status: EventDeliveryStatus;
    /**
     * The payload this delivery carries — the exact bytes sent on the wire,
     * replayed identically across every retry. Exposed so callers can see
     * what the delivery is about without cross-referencing other resources.
     *
     * Shape per delivery type:
     * - webhook effect: signed `LedgerRecord<LedgerEvent>`
     * - bridge effect: signed `LedgerRecord<LedgerEvent>`
     * - DTC bridge message (prepare / commit / abort / status): signed
     *   `LedgerRecord<BridgeCommand>` (no LedgerEvent exists for these — the
     *   command is the closest analog)
     */
    output?: EventDeliveryOutput;
};
